 210→var results []Result
 211→
 212→func fmtDur(d time.Duration) string {
 213→	if d < time.Second {
 214→		return fmt.Sprintf("%dms", d.Milliseconds())
 215→	}
 216→	return fmt.Sprintf("%.1fs", d.Seconds())
 217→}
