		run(client, "mkdir -p ~/dockyard-nested-test")
		_, se, code := run(client, fmt.Sprintf(
			"DOCKYARD_ENV=%s DOCKYARD_ROOT=%s DOCKYARD_DOCKER_PREFIX=%s ~/dockyard.sh gen-env",
