)

// ── Instance descriptor ───────────────────────────────────────────────────────

type Instance struct {
	Label   string // "A", "B", "C"
	Prefix  string // "dy1_"
	Root    string // "/dy1"
	EnvFile string // "~/dy1.env"
	Socket  string // "/dy1/run/docker.sock"
