	run(client, "sudo rm -f /etc/systemd/system/dyn_docker.service 2>/dev/null; true")
	run(client, "rm -rf ~/dockyard-nested-test 2>/dev/null; true")
	run(client, "sudo systemctl daemon-reload 2>/dev/null; true")
